# Prompt: Build a Flask API endpoint for searching products. Users can search by keyword with GET /api/search?q=keyword. Query returns matching products from Elasticsearch. This is our primary search API that needs to handle high traffic during sales events.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch
from functools import wraps
import os
import time
from datetime import datetime

app = Flask(__name__)

es_host = os.getenv('ELASTICSEARCH_HOST', 'localhost')
es_port = int(os.getenv('ELASTICSEARCH_PORT', 9200))
es_index = os.getenv('ELASTICSEARCH_INDEX', 'products')

es = Elasticsearch([{'host': es_host, 'port': es_port, 'scheme': 'http'}])

def cache_response(timeout=300):
    def decorator(f):
        cache = {}
        @wraps(f)
        def decorated_function(*args, **kwargs):
            cache_key = request.full_path
            current_time = time.time()
            
            if cache_key in cache:
                cached_data, timestamp = cache[cache_key]
                if current_time - timestamp < timeout:
                    return cached_data
            
            result = f(*args, **kwargs)
            cache[cache_key] = (result, current_time)
            
            if len(cache) > 1000:
                oldest_key = min(cache.keys(), key=lambda k: cache[k][1])
                del cache[oldest_key]
            
            return result
        return decorated_function
    return decorator

@app.route('/api/search', methods=['GET'])
@cache_response(timeout=60)
def search_products():
    query = request.args.get('q', '').strip()
    page = request.args.get('page', 1, type=int)
    per_page = request.args.get('per_page', 20, type=int)
    
    if not query:
        return jsonify({
            'error': 'Query parameter "q" is required',
            'status': 'error'
        }), 400
    
    if per_page > 100:
        per_page = 100
    
    if page < 1:
        page = 1
    
    from_index = (page - 1) * per_page
    
    try:
        search_body = {
            'query': {
                'bool': {
                    'should': [
                        {
                            'multi_match': {
                                'query': query,
                                'fields': ['name^3', 'description^2', 'category', 'brand', 'tags'],
                                'type': 'best_fields',
                                'fuzziness': 'AUTO'
                            }
                        },
                        {
                            'match_phrase': {
                                'name': {
                                    'query': query,
                                    'boost': 5
                                }
                            }
                        }
                    ],
                    'minimum_should_match': 1
                }
            },
            'from': from_index,
            'size': per_page,
            'sort': [
                '_score',
                {'created_at': {'order': 'desc'}}
            ],
            'highlight': {
                'fields': {
                    'name': {},
                    'description': {}
                },
                'pre_tags': ['<em>'],
                'post_tags': ['</em>']
            }
        }
        
        response = es.search(index=es_index, body=search_body)
        
        hits = response['hits']['hits']
        total = response['hits']['total']
        
        if isinstance(total, dict):
            total_count = total['value']
        else:
            total_count = total
        
        products = []
        for hit in hits:
            product = hit['_source']
            product['id'] = hit['_id']
            product['score'] = hit['_score']
            
            if 'highlight' in hit:
                product['highlight'] = hit['highlight']
            
            products.append(product)
        
        total_pages = (total_count + per_page - 1) // per_page
        
        return jsonify({
            'status': 'success',
            'query': query,
            'results': products,
            'pagination': {
                'page': page,
                'per_page': per_page,
                'total': total_count,
                'total_pages': total_pages,
                'has_next': page < total_pages,
                'has_prev': page > 1
            },
            'took': response['took'],
            'timestamp': datetime.utcnow().isoformat()
        }), 200
        
    except Exception as e:
        app.logger.error(f'Search error: {str(e)}')
        return jsonify({
            'error': 'Search failed',
            'status': 'error',
            'message': str(e)
        }), 500

@app.route('/api/health', methods=['GET'])
def health_check():
    try:
        es.ping()
        return jsonify({
            'status': 'healthy',
            'elasticsearch': 'connected',
            'timestamp': datetime.utcnow().isoformat()
        }), 200
    except Exception as e:
        return jsonify({
            'status': 'unhealthy',
            'elasticsearch': 'disconnected',
            'error': str(e),
            'timestamp': datetime.utcnow().isoformat()
        }), 503

@app.errorhandler(404)
def not_found(error):
    return jsonify({
        'error': 'Endpoint not found',
        'status': 'error'
    }), 404

@app.errorhandler(500)
def internal_error(error):
    return jsonify({
        'error': 'Internal server error',
        'status': 'error'
    }), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)